import pandas as pd
import re
from datetime import datetime

def main(leads_df):
    df = pd.DataFrame(leads_df)

    # 1. 去重
    df = df.drop_duplicates(subset=['lead_id'], keep='first')

    # 2. 联系方式标准化
    def clean_contact(contact):
        if pd.isna(contact):
            return ''
        contact = str(contact)
        # 移除所有非数字字符
        digits = re.sub(r'\D', '', contact)
        return digits

    df['contact_clean'] = df['contact'].apply(clean_contact)

    # 3. 预算字段处理
    def clean_budget(budget):
        if pd.isna(budget):
            return 0.0
        if isinstance(budget, str):
            # 移除货币符号和逗号
            budget = re.sub(r'[^\d.]', '', budget)
        try:
            return float(budget)
        except:
            return 0.0

    df['budget_clean'] = df['budget'].apply(clean_budget)

    # 4. 时间字段标准化
    def parse_time(time_str):
        if pd.isna(time_str):
            return datetime.now().isoformat()
        try:
            # 尝试多种格式解析
            for fmt in ['%Y-%m-%d %H:%M:%S', '%Y/%m/%d %H:%M:%S', '%Y-%m-%d', '%Y/%m/%d']:
                try:
                    dt = datetime.strptime(str(time_str), fmt)
                    return dt.isoformat()
                except:
                    continue
            return datetime.now().isoformat()
        except:
            return datetime.now().isoformat()

    df['create_time_clean'] = df['create_time'].apply(parse_time)

    # 5. 来源分类
    def categorize_source(source):
        if pd.isna(source):
            return '其他'
        source = str(source).lower()
        if '官网' in source or 'website' in source:
            return '官网'
        elif '活动' in source or 'event' in source:
            return '市场活动'
        elif '广告' in source or 'ad' in source:
            return '广告投放'
        elif '转介绍' in source or 'referral' in source:
            return '转介绍'
        else:
            return '其他'

    df['source_category'] = df['source'].apply(categorize_source)

    return {
        'cleaned_leads': df.to_dict('records')
